import{_ as a,o as s,c as o,ah as i}from"./chunks/framework.Bi9enVNS.js";const u=JSON.parse('{"title":"Common Workflows","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/workflows.md","filePath":"en/guide/workflows.md","lastUpdated":1774205896000}'),t={name:"en/guide/workflows.md"};function l(n,e,r,d,c,p){return s(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="common-workflows" tabindex="-1">Common Workflows <a class="header-anchor" href="#common-workflows" aria-label="Permalink to &quot;Common Workflows&quot;">​</a></h1><p>This page breaks the current reference implementation into five practical steps.</p><h2 id="_1-ingest-sample-logs" tabindex="-1">1. Ingest sample logs <a class="header-anchor" href="#_1-ingest-sample-logs" aria-label="Permalink to &quot;1. Ingest sample logs&quot;">​</a></h2><p>Use the sender or a sample file to push one batch into the server:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./cmd/vlt-sender</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -token</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -environment</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> json</span></span></code></pre></div><p>To demo different topology shapes, start with these files:</p><ul><li><code>examples/upload.json</code></li><li><code>examples/upload-fanout.json</code></li><li><code>examples/upload-retry-loop.json</code></li><li><code>examples/upload-bus-handoff.json</code></li></ul><h2 id="_2-search-logs" tabindex="-1">2. Search logs <a class="header-anchor" href="#_2-search-logs" aria-label="Permalink to &quot;2. Search logs&quot;">​</a></h2><p>The log search endpoint is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /v1/logs/search</span></span></code></pre></div><p>Supported filters:</p><ul><li><code>project</code></li><li><code>environment</code></li><li><code>source_type</code></li><li><code>source_name</code></li><li><code>severity_number</code></li><li><code>trace_id</code></li><li><code>keyword</code></li><li><code>start</code></li><li><code>end</code></li></ul><p>Typical usage:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://localhost:8080/v1/logs/search?project=demo&amp;trace_id=0123456789abcdef0123456789abcdef&quot;</span></span></code></pre></div><h2 id="_3-open-a-trace" tabindex="-1">3. Open a trace <a class="header-anchor" href="#_3-open-a-trace" aria-label="Permalink to &quot;3. Open a trace&quot;">​</a></h2><p>Once you have a <code>trace_id</code>, continue with:</p><ul><li><code>GET /v1/traces/{trace_id}</code></li><li><code>GET /v1/traces/{trace_id}/timeline</code></li><li><code>GET /v1/traces/{trace_id}/topology</code></li></ul><p>The frontend Logs Explorer follows the same path when a row has a trace.</p><h2 id="_4-inspect-timeline-and-topology" tabindex="-1">4. Inspect timeline and topology <a class="header-anchor" href="#_4-inspect-timeline-and-topology" aria-label="Permalink to &quot;4. Inspect timeline and topology&quot;">​</a></h2><h3 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h3><ul><li>Every lane maps to one <code>source_fingerprint</code></li><li>Each lane contains events, error count, and first/last seen timestamps</li><li>Lanes are ordered by <code>first_seen</code></li></ul><h3 id="topology" tabindex="-1">Topology <a class="header-anchor" href="#topology" aria-label="Permalink to &quot;Topology&quot;">​</a></h3><ul><li>Nodes are grouped by <code>source_fingerprint</code></li><li>Edges are derived from adjacent source segments inside the trace</li><li>Consecutive identical sources are collapsed before edges are emitted</li><li>Error counting is based on <code>severity_number &gt;= 17</code></li></ul><h2 id="_5-browse-sources" tabindex="-1">5. Browse sources <a class="header-anchor" href="#_5-browse-sources" aria-label="Permalink to &quot;5. Browse sources&quot;">​</a></h2><p>The sources view answers “which source instances are currently writing logs?”:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /v1/sources</span></span></code></pre></div><p>Its structure is:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source_type -&gt; source_name -&gt; instance_id</span></span></code></pre></div><p>If a record has no <code>instance_id</code>, the current implementation exposes it as <code>-</code>.</p><h2 id="one-recommended-end-to-end-path" tabindex="-1">One recommended end-to-end path <a class="header-anchor" href="#one-recommended-end-to-end-path" aria-label="Permalink to &quot;One recommended end-to-end path&quot;">​</a></h2><ol><li>Start the backend</li><li>Send one sample batch</li><li>Confirm it via <code>GET /v1/logs/search</code></li><li>Pick a <code>trace_id</code></li><li>Open timeline and topology</li><li>Use the sources view to inspect instance coverage</li></ol><h2 id="sources-of-truth" tabindex="-1">Sources of truth <a class="header-anchor" href="#sources-of-truth" aria-label="Permalink to &quot;Sources of truth&quot;">​</a></h2><ul><li><code>internal/api/http.go</code></li><li><code>internal/store/store.go</code></li><li><code>internal/store/memory/memory.go</code></li><li><code>web/src/App.jsx</code></li></ul>',33)])])}const m=a(t,[["render",l]]);export{u as __pageData,m as default};
